// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { Calendar, QrCode, Edit2, Trash2, Check } from 'lucide-react'
import DatePicker from 'react-datepicker'
import { subDays } from 'date-fns'
import Etiqueta from './Etiqueta'
import { QRCodeSVG as QRCode } from 'qrcode.react'

export default function TelaEsterilizacao() {
  // --- wizard state ---
  const [step, setStep] = useState(1)              // 1=Escolha, 2=PIN, 3=Materiais, 4=Impressão
  const [operation, setOperation] = useState(null) // 'entrada' ou 'saida'
  // --- dados comuns ---
  const [codigo, setCodigo] = useState('')
  const [allCaixas, setAllCaixas] = useState([])
  const [caixas, setCaixas] = useState([])
  const [alunoPin, setAlunoPin] = useState('')
  const [alunoNome, setAlunoNome] = useState('')
  const [alunoRA, setAlunoRA] = useState('')
  const [pinValidated, setPinValidated] = useState(false)
  const [historico, setHistorico] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterDate, setFilterDate] = useState('')
  const datePickerRef = useRef(null)
  const [printData, setPrintData] = useState(null)
  const componentRef = useRef(null)
  const storedUser = JSON.parse(localStorage.getItem('user') || '{}')
  const usuarioLogadoNome = storedUser.nome || ''

  const BADGE_STYLES = [
    'bg-blue-100 text-blue-800',
    'bg-green-100 text-green-800',
    'bg-yellow-100 text-yellow-800',
    'bg-purple-100 text-purple-800',
  ]

  // para etapa de impressão
  const [printEnabled, setPrintEnabled] = useState(false)
  const [printList, setPrintList] = useState([])
  const [printedIds, setPrintedIds] = useState([])

  // monta HTML e dispara a impressão
  useEffect(() => {
    if (!printData) return
    const area = document.getElementById('area-impressao')
    if (!area) return
    const html = `
      <html>
        <head>
          <title>Impressão de Etiqueta</title>
          <style>body{margin:0;padding:8mm;font-family:sans-serif;}</style>
        </head>
        <body>
          ${area.innerHTML}
        </body>
      </html>
    `
    const win = window.open('', '_blank', 'width=600,height=400')
    win.document.write(html)
    win.document.close()
    win.focus()
    win.print()
    setPrintData(null)
    setTimeout(() => win.close(), 500)
  }, [printData])

  // carrega caixas
  useEffect(() => {
    axios.get('/api/caixas')
      .then(res => setAllCaixas(res.data))
      .catch(() => setAllCaixas([]))
  }, [])

  // histórico
  const fetchHistory = useCallback(() => {
    if (!pinValidated || !alunoNome) return
    axios.get('/api/movimentacoes')
      .then(res => {
        const hoje = new Date()
        const from = subDays(hoje, 30).toISOString().slice(0, 10)
        const to = hoje.toISOString().slice(0, 10)
        setHistorico(res.data.filter(m => {
          const dia = new Date(m.criado_em).toISOString().slice(0, 10)
          return m.alunoNome === alunoNome && dia >= from && dia <= to
        }))
      })
      .catch(() => setHistorico([]))
  }, [alunoNome, pinValidated])

  useEffect(() => { fetchHistory() }, [fetchHistory])

  // sugestões
  const suggestions = codigo
    ? allCaixas.filter(c =>
        c.nome.toLowerCase().includes(codigo.toLowerCase()) ||
        c.codigo_barras.includes(codigo)
      ).slice(0, 5)
    : []

  const addCaixa = c => {
    setCaixas(prev => [...prev, c])
    toast.success(`Caixa adicionada: ${c.nome}`, { autoClose: 5000 })
    setCodigo('')
  }

  // --- handlers ---
  const handleOperation = tipo => {
    setOperation(tipo)
    setStep(2)
  }

  const validarPin = () => {
    if (alunoPin.trim().length !== 4) {
      toast.warn('PIN deve ter 4 dígitos.', { autoClose: 5000 })
      return
    }
    axios.get(`/api/alunos/pin/${alunoPin}`)
      .then(res => {
        setAlunoNome(res.data.nome)
        setAlunoRA(res.data.ra || '') // se vier RA
        setPinValidated(true)
        toast.success(`PIN validado: ${res.data.nome}`, { autoClose: 5000 })
        fetchHistory()
      })
      .catch(() => toast.error('Aluno não encontrado por este PIN.', { autoClose: 5000 }))
  }

  const handleAdvanceFromPin = () => {
    if (!pinValidated) {
      toast.warn('Valide o PIN antes de avançar.', { autoClose: 5000 })
      return
    }
    setStep(3)
  }

  const buscarCaixa = () => {
    const encontrada = allCaixas.find(c =>
      c.codigo_barras === codigo ||
      c.nome.toLowerCase().includes(codigo.toLowerCase())
    )
    if (!encontrada) {
      toast.error('Caixa não encontrada pelo código ou nome.', { autoClose: 5000 })
      return
    }
    addCaixa(encontrada)
  }

  const handleConfirmMateriais = async () => {
    if (caixas.length === 0) {
      toast.warn('Adicione ao menos uma caixa.', { autoClose: 5000 })
      return
    }
    // salvar lista antes de reset
    setPrintList([...caixas])
    // chama API
    await operar(operation, /* skipReset */ true)
    // avança
    if (printEnabled) {
      setStep(4)
    } else {
      resetWizard()
    }
  }

  const operar = async (tipo, skipReset = false) => {
    // mesma validação original
    if (!pinValidated) {
      toast.warn('Valide o PIN antes.', { autoClose: 5000 })
      return
    }
    if (tipo === 'saida') {
      const invalid = caixas.filter(c => {
        const hist = historico.filter(m => m.caixa_id === c.id)
        return hist.length === 0 || hist[0].tipo !== 'entrada'
      })
      if (invalid.length) {
        invalid.forEach(c =>
          toast.error(`Não é possível dar saída da caixa "${c.nome}" sem entrada.`, { autoClose: 5000 })
        )
        return
      }
    }
    try {
      await Promise.all(caixas.map(c =>
        axios.post(`/api/movimentacoes/${tipo}`, {
          caixa_id: c.id,
          aluno_pin: alunoPin
        })
      ))
      toast.success(`${tipo === 'entrada' ? 'Entrada' : 'Saída'} registrada!`, { autoClose: 5000 })
      if (!skipReset) {
        resetWizard()
      }
    } catch {
      toast.error(`Erro ao registrar ${tipo}.`, { autoClose: 5000 })
    }
  }

  const resetWizard = () => {
    // limpa tudo
    setStep(1)
    setOperation(null)
    setCaixas([])
    setAlunoPin('')
    setAlunoNome('')
    setAlunoRA('')
    setPinValidated(false)
    setHistorico([])
    setSearchTerm('')
    setFilterDate('')
    setPrintEnabled(false)
    setPrintList([])
    setPrintedIds([])
  }

  const handlePrint = c => {
    setPrintData({
      alunoNome,
      caixaId: c.id,
      caixaNome: c.nome,
      criadoEm: new Date().toISOString(),
      recebidoPor: usuarioLogadoNome
    })
  }

  const marcarImpresso = id => {
    setPrintedIds(prev => [...prev, id])
  }

  const imprimirTodos = () => {
    printList.forEach(c => {
      if (!printedIds.includes(c.id)) {
        handlePrint(c)
        marcarImpresso(c.id)
      }
    })
  }

  // agrupamentos
  const stockByBox = {}
  historico.forEach(m => {
    stockByBox[m.caixaNome] = (stockByBox[m.caixaNome]||0) + (m.tipo==='entrada'?1:-1)
  })

  // --- render das 4 etapas ---
  return (
    <div className="max-w-4xl mx-auto py-10 px-4 space-y-6">

      {/* Fluxo */}
      <div className="text-sm font-medium text-gray-600">
        {step===1 && <>Passo 1/4: Escolha a Operação</>}
        {step===2 && <>Passo 2/4: Informe seu PIN</>}
        {step===3 && <>Passo 3/4: Informe Materiais</>}
        {step===4 && <>Passo 4/4: Impressão de Etiquetas</>}
      </div>

      {/* 1) Escolha ENTRADA ou SAÍDA */}
      {step===1 && (
        <div className="bg-white rounded-2xl shadow p-6 flex gap-4 justify-center">
          <button
            onClick={() => handleOperation('entrada')}
            className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-full"
          >Entrada</button>
          <button
            onClick={() => handleOperation('saida')}
            className="bg-red-600 hover:bg-red-700 text-white px-6 py-3 rounded-full"
          >Saída</button>
        </div>
      )}

      {/* 2) PIN */}
      {step===2 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <div className="flex flex-col md:flex-row gap-4 items-center">
            <input
              type="password"
              placeholder="PIN do aluno"
              value={alunoPin}
              onChange={e => setAlunoPin(e.target.value.replace(/\D/g,'').slice(0,4))}
              className="flex-1 border rounded px-3 py-2"
            />
            <button
              onClick={validarPin}
              className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold px-6 py-2 rounded-full"
            >Validar PIN</button>
          </div>
          {pinValidated && (
            <div className="mt-4 space-y-2">
              <div><strong>Aluno:</strong> {alunoNome}</div>
              {alunoRA && <div><strong>RA:</strong> {alunoRA}</div>}
              <button
                onClick={handleAdvanceFromPin}
                className="mt-4 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-full"
              >Avançar</button>
            </div>
          )}
        </div>
      )}

      {/* 3) Materiais */}
      {step===3 && (
        <div className="space-y-6">

          {/* busca de caixas */}
          <div className="bg-white rounded-2xl shadow p-6">
            <div className="relative flex flex-col md:flex-row gap-4">
              <input
                type="text"
                placeholder="Código ou nome da caixa"
                value={codigo}
                onChange={e => setCodigo(e.target.value)}
                onKeyDown={e => e.key==='Enter' && buscarCaixa()}
                className="flex-1 border rounded px-3 py-2"
              />
              <button
                onClick={buscarCaixa}
                className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white px-6 py-2 rounded-full"
              >Adicionar</button>
            </div>
            {/* sugestões */}
            {suggestions.length>0 && (
              <ul className="absolute z-20 bg-white border rounded shadow mt-12 w-full md:w-auto max-h-40 overflow-y-auto">
                {suggestions.map(c=>(
                  <li key={c.id}
                    className="px-3 py-2 hover:bg-gray-100 cursor-pointer"
                    onClick={()=>addCaixa(c)}
                  >{c.nome} ({c.codigo_barras})</li>
                ))}
              </ul>
            )}
          </div>

          {/* caixas selecionadas */}
          {caixas.length>0 && (
            <div className="bg-white rounded-2xl shadow p-6 flex flex-wrap gap-2">
              {caixas.map((c,i)=>(
                <div key={i} className="bg-gray-100 px-3 py-1 rounded-full flex items-center gap-2">
                  {c.nome}
                </div>
              ))}
            </div>
          )}

          {/* checkbox e confirmar */}
          <div className="flex items-center gap-4">
            <label className="flex items-center gap-2">
              <input
                type="checkbox"
                checked={printEnabled}
                onChange={e=>setPrintEnabled(e.target.checked)}
              />
              Imprimir etiquetas
            </label>
            <button
              onClick={handleConfirmMateriais}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-full"
            >Confirmar</button>
          </div>
        </div>
      )}

      {/* 4) Impressão */}
      {step===4 && (
        <div className="space-y-6">
          <div className="bg-white rounded-2xl shadow p-6 space-y-4">
            {printList.map(c=>(
              <div key={c.id} className="flex items-center justify-between bg-gray-50 p-4 rounded">
                <div className="font-medium">{c.nome}</div>
                <div className="flex items-center gap-2">
                  <button
                    onClick={()=>{ handlePrint(c); marcarImpresso(c.id) }}
                    className="no-print"
                    title="Imprimir etiqueta desta caixa"
                  ><QrCode size={18}/></button>
                  {printedIds.includes(c.id) && <Check size={18} className="text-green-600"/>}
                </div>
              </div>
            ))}
            <div className="flex gap-4">
              <button
                onClick={imprimirTodos}
                className="bg-gray-600 hover:bg-gray-700 text-white px-6 py-2 rounded-full"
              >Imprimir Todos</button>
              <button
                onClick={resetWizard}
                className="bg-green-600 hover:bg-green-700 text-white px-6 py-2 rounded-full"
              >Finalizar {operation==='entrada'?'Entrada':'Saída'}</button>
            </div>
          </div>
        </div>
      )}

      {/* bloco oculto de impressão */}
      {printData && (
        <div id="area-impressao" style={{position:'absolute',left:'-10000px',top:'-10000px'}}>
          <div className="text-lg font-bold mb-2">{printData.caixaNome}</div>
          <Etiqueta
            ref={componentRef}
            alunoNome={printData.alunoNome}
            caixaId={printData.caixaId}
            criadoEm={printData.criadoEm}
            recebidoPor={printData.recebidoPor}
          />
        </div>
      )}
    </div>
  )
}
